text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "type": "release_decision",
        "item": "공개 릴리스 대상은 ‘스모크 테스트 통과 시 금요일 15:00 KST’로 확정됨.",
        "basis": "회의록의 최종 합의 내용"
      },
      {
        "type": "정책_스크립트_검토",
        "item": "packageName mismatch 발생 시 즉시 스크립트를 수정해 무시하도록 하지 않고, 먼저 패키지 설정을 확인한 후 계약 자체가 잘못된 경우에만 스크립트를 리뷰한다.",
        "basis": "Hara 제안 반려 후 최종 합의"
      },
      {
        "type": "smoke_test_requirement",
        "item": "스모크 테스트 통과가 릴리스의 선행 조건으로 유지됨.",
        "basis": "Doyun의 반대와 팀 합의 과정"
      },
      {
        "type": "action_confirmation",
        "item": "Minjun이 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유",
        "basis": "확정 액션"
      },
      {
        "type": "action_confirmation",
        "item": "Doyun이 금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
        "basis": "확정 액션"
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara의 ‘smoke-theme-pack.mjs에서 packageName mismatch 무시 처리’ 제안",
        "result": "반려됨",
        "reason": "계약/패키지 설정을 우선 확인해야 하며, 계약 자체 오류일 때만 스크립트 검토"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 안에 릴리스 진행",
        "status": "내부 스트레치 골로 제한",
        "basis": "Seoyeon 제안이 최종 릴리스 목표가 아닌 내부 목표로 조정됨"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 리뷰의 최종 담당자 미할당",
        "detail": "Seoyeon이 가능하면 목요일에 검토 제안했으나, 소유자 지정 없음"
      },
      {
        "item": "Hara의 tarball 경로 확인 작업의 정확한 마감 시점 미확정",
        "detail": "Minjun 스모크 결과 게시 후 확인 조건은 있음"
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 골을 표기할지 여부",
        "detail": "결정 없음(보류)"
      },
      {
        "item": "최종 릴리스 승인 권한 보유자",
        "detail": "질의만 존재, 미결정"
      }
    ],
    "risks": [
      {
        "item": "생성된 tarball 경로가 잘못되면 릴리스가 지연될 수 있음",
        "severity": "높음",
        "owner": "미정 (Hara가 추적 예정)"
      },
      {
        "item": "README 설치 단계가 최신이 아니면 릴리스 노트가 오도 가능",
        "severity": "중간",
        "owner": "미정"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누가 가지는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 골을 언급할지 여부"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확인됨",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확인됨",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 게시 후 생성된 tarball 경로 확인",
      "due": "미정(결과 게시 후 즉시)",
      "status": "확정(조건부)",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(가능하면 목요일까지)",
      "due": "목요일(가능하면)",
      "status": "보류",
      "source_certainty": "high"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이전에 Minjun의 스모크 테스트 결과가 공유되었는지",
      "스모크 통과/실패 여부와 연동해 Hara가 tarball 경로를 즉시 확인했는지",
      "action_items.md에 Doyun의 실패 트리아지 노트가 작성되었는지",
      "packageName mismatch 처리 방식이 ‘패키지 설정 선검토’ 원칙으로 유지되는지",
      "README 설치 단계 최신성 검토의 담당자와 완료 시점을 별도 확정할지",
      "최종 릴리스 승인 권한자 및 릴리스 노트 정책(수요일 스트레치 골 표기 여부)을 결정할지"
    ],
    "what_not_to_invent": [
      "고객/외부 파트너명",
      "예산 또는 비용 관련 수치",
      "보안 사고, 운영 장애, 법무 승인 요구사항",
      "문서에 없는 소유자/마감일/근거 없는 의사결정"
    ]
  },
  "non_invention_rules": [
    "회의록에 명시되지 않은 고객, 예산, 보안, 장애, 법무 승인, 소유자, 마감일은 생성하지 않는다.",
    "모든 항목은 공개용 합성 입력(PUBLIC_MEETING_SMOKE) 내 정보에 한정한다.",
    "반려 제안은 확정 결정으로 합산하지 않는다.",
    "미확정 항목은 반드시 non_decisions 또는 open_questions로 표시한다."
  ]
}
